// 映射room名称到实际的Matrix Room ID
const body = $input.first().json.body || $input.first().json;
const roomName = body.room;
const message = body.message;
const html = body.html || null;

const roomMap = {
  'alerts': $env.MATRIX_ROOM_ALERTS,
  'daily': $env.MATRIX_ROOM_DAILY,
  'todo': $env.MATRIX_ROOM_TODO,
  'qa': $env.MATRIX_ROOM_QA
};

const roomId = roomMap[roomName];

if (!roomId) {
  throw new Error(`Unknown room: ${roomName}. Valid rooms: alerts, daily, todo, qa`);
}

if (!message) {
  throw new Error('Message is required');
}

// 生成唯一的事务ID
const txnId = `n8n_${Date.now()}_${Math.random().toString(36).substring(2, 10)}`;

// 构建Matrix消息体
const matrixBody = {
  msgtype: 'm.text',
  body: message
};

// 如果有HTML格式，添加formatted_body
if (html) {
  matrixBody.format = 'org.matrix.custom.html';
  matrixBody.formatted_body = html;
} else {
  matrixBody.format = 'org.matrix.custom.html';
  matrixBody.formatted_body = message;
}

return [{
  json: {
    roomId: roomId,
    txnId: txnId,
    matrixBody: matrixBody,
    encodedRoomId: encodeURIComponent(roomId)
  }
}];

// 检查发送结果
const response = $input.first().json;

if (response.event_id) {
  return [{
    json: {
      status: 'sent',
      event_id: response.event_id
    }
  }];
} else {
  return [{
    json: {
      status: 'error',
      error: response.errcode || 'Unknown error',
      message: response.error || JSON.stringify(response)
    }
  }];
}
